                end = u.find("'", start + 1)
                if end != -1:
                    uncertainties_set.add(norm(u[start + 1 : end]))
                else:
                    uncertainties_set.add(norm(u))
            else:
                uncertainties_set.add(norm(u))
        elif isinstance(u, dict):
            name = u.get("name") or u.get("container") or u.get("object")
            if name:
                uncertainties_set.add(norm(name))

    subgoal = (getattr(wm, "current_subgoal", None) or getattr(wm, "subgoal", "") or "")
    task = getattr(wm, "task", "") or ""
    inventory = getattr(wm, "inventory", []) or []

    # Phase flags
    want_find = ("find" in subgoal.lower()) or ("clean" in task.lower() and not inventory)
    need_mug = ("mug" in task.lower())
    have_mug = any("mug" in (str(it).lower()) for it in inventory)

    def is_target_receptacle(cmd_low: str) -> bool:
        return any(k in cmd_low for k in ["coffeemachine", "coffee machine", "coffee_maker", "coffee maker"])

    # If an "open X" is admissible, we are already at X; prioritize opening before leaving
    here_open_targets: List[str] = []
    for c in admissible_commands:
        cl = c.lower().strip()
        if cl.startswith("open "):
            here_open_targets.append(norm(c[5:]))
    any_open_here = len(here_open_targets) > 0

    for cmd in admissible_commands:
