        if low.startswith("inventory"):
            s += 0.02

        # Directly grabbing the mug is best
        if ("mug" in low) and ("take" in low or low.startswith("pick up") or "grab" in low):
            s += 3.0

        # Opening a nearby container is usually the right next step, especially during find phase
        if low.startswith("open "):
