            # Prefer likely mug locations when searching
            if need_mug and want_find:
                if is_cab:
                    s += 0.5
                elif is_draw:
                    s -= 0.2
                elif is_counter or is_table:
                    s += 0.07

            # Strongly prefer unknown containers
            if target in uncertainties_set:
                s += 1.2 if (need_mug and is_cab) else 0.9

            # Downweight moving to containers we've already searched
            if target in containers_searched:
                s -= 0.8

            # Don't rush to the target receptacle before acquiring the object
            if not have_mug and is_target_receptacle(low):
                s -= 0.6

            # If we can open something right here, discourage leaving even more
            if any_open_here:
                s -= 1.0

            # Visiting sink during find phase is premature
            if want_find and is_sink and not have_mug:
                s -= 0.35

            # Small bias towards lower-indexed containers to impose a consistent order
            import re
            m = re.search(r"(\d+)", target)
            if m:
